_sage_const_20000 = Integer(20000); _sage_const_0 = Integer(0); _sage_const_1 = Integer(1); _sage_const_2 = Integer(2); _sage_const_3 = Integer(3); _sage_const_5 = Integer(5); _sage_const_7 = Integer(7); _sage_const_11 = Integer(11); _sage_const_13 = Integer(13)# 構成例で strict ケース(精密公式が lcm_all より真に小)を実演。
# T = block_diag(A,...,A [p 個], B): A の固有値は重複度 p (≡0 mod p)で脱落 → π は B の order のみ。
def trace_period_mod_p(T,p,maxN=_sage_const_20000 ):
    R=GF(p); Tm=T.change_ring(R); seenM={}; N=_sage_const_0 ; Pk=identity_matrix(R,T.nrows())
    while N<=maxN:
        Pk=Pk*Tm; N+=_sage_const_1 ; key=tuple(Pk.list())
        if key in seenM:
            pre=seenM[key]; per=N-seenM[key]
            tr=[ZZ((Tm**j).trace()) for j in range(_sage_const_1 ,pre+_sage_const_2 *per+_sage_const_1 )]
            for d in divisors(per):
                if all(tr[i]==tr[i+d] for i in range(pre,len(tr)-d-_sage_const_1 )): return d
            return per
        seenM[key]=N
    return None
def om(T,p):
    R=GF(p); cp=T.charpoly().change_ring(R); res=[]
    for f,mult in cp.factor():
        d=f.degree(); Fq=GF(p**d,'a')
        for r,_ in f.change_ring(Fq).roots():
            if r!=_sage_const_0 : res.append((r.multiplicative_order(),mult))
    return res
def lcm_all(o): 
    L=_sage_const_1 
    for x,m in o: L=lcm(L,x)
    return L
def lcm_ref(o,p):
    L=_sage_const_1 
    for x,m in o:
        if m%p!=_sage_const_0 : L=lcm(L,x)
    return L
R = ZZ['x']; (x,) = R._first_ngens(1)
A=companion_matrix(x**_sage_const_2 -_sage_const_3 *x+_sage_const_1 )   # 固有値 order は p による
B=companion_matrix(x-_sage_const_2 )
for p in [_sage_const_5 ,_sage_const_7 ,_sage_const_11 ,_sage_const_13 ]:
    blocks=[A]*p+[B]
    T=block_diagonal_matrix(blocks)
    pi=trace_period_mod_p(T,p); o=om(T,p)
    print(f" p={p}: T=diag(A×{p},B); π(p,1)={pi}, lcm_refined={lcm_ref(o,p)}, lcm_all={lcm_all(o)}  strict={lcm_ref(o,p)<lcm_all(o)}, π=refined: {pi==lcm_ref(o,p)}")

